// Names in data.js may carry invisible direction marks — normalize.
function natKey(name) {
  return String(name).replace(/[\u200e\u200f\u202a-\u202e\ufeff]/g, '')
    .replace(/\s+/g, ' ').trim();
}
function playerNats(name) { return PLAYER_NATS[natKey(name)] ?? []; }

// All countries appearing in the data (for the admin mission editor).
